#include <stdio.h>

int main()
{
	int n, i, sum = 0;
	char s[51];

	scanf ("%d %s", &n, s);

	for (i = 0; i < n/2 && (s[i] == '4' || s[i] == '7'); i++)
		sum += s[i] - '0';

	if (i == n/2)
		for (; i < n && (s[i] == '4' || s[i] == '7'); i++)
			sum -= s[i] - '0';

	puts (sum == 0 && i == n ? "YES" : "NO");		

	return 0;
}

