use std::io;
use std::str::FromStr;

fn get_num() -> usize {
    let mut input = String::new();

    io::stdin().read_line(&mut input).expect("");

    usize::from_str(input.trim()).unwrap()
}

fn get_string() -> String {
    let mut input = String::new();

    io::stdin().read_line(&mut input).expect("");

    input.trim().to_string()
}

fn main() {
    let n = get_num();
    let s = get_string();

    for c in s.chars() {
        if c != '4' && c != '7' {
            println!("NO");
            return;
        }
    }

    let mut fs = 0;
    let mut ss = 0;
    for (i, c) in s.chars().enumerate() {
        if i == n / 2 {
            break;
        }
        fs += c.to_digit(10).unwrap();
    }

    for (_, c) in s.chars().enumerate().skip(n / 2) {
        ss += c.to_digit(10).unwrap();
    }

    if fs == ss {
        println!("YES");
    } else {
        println!("NO");
    }
}
